<?php
declare(strict_types=1);
if (! defined('ABSPATH')) { fwrite(STDERR, "WordPress must be loaded.\n"); exit(1); }
$theme_root=dirname(__DIR__).'/theme';$files=[];foreach(['templates','parts'] as $directory){$iterator=new RecursiveIteratorIterator(new RecursiveDirectoryIterator($theme_root.'/'.$directory));foreach($iterator as $file){if($file->isFile()&&strtolower($file->getExtension())==='html'){$files[]=$file->getPathname();}}}$errors=[];$inspect=static function(array $blocks,string $file)use(&$inspect,&$errors):void{foreach($blocks as $block){if(($block['blockName']??null)===null&&trim((string)($block['innerHTML']??''))!==''){$errors[]=basename($file).': unparsed top-level HTML';}if(!empty($block['innerBlocks'])){$inspect($block['innerBlocks'],$file);}}};foreach($files as $file){$blocks=parse_blocks((string)file_get_contents($file));if(!$blocks){$errors[]=basename($file).': no blocks parsed';continue;}$inspect($blocks,$file);}if($errors){fwrite(STDERR,implode("\n",$errors)."\n");exit(1);}echo wp_json_encode(['validated'=>count($files),'status'=>'pass'],JSON_PRETTY_PRINT).PHP_EOL;
